import subprocess, json

result = subprocess.run(['dotnet', 'package', 'list', '--format', 'json'], capture_output=True, text=True)
after = json.loads(result.stdout)
with open('after-cpm-packages.json', 'w') as f:
    json.dump(after, f, indent=2)

with open('baseline-packages.json') as f:
    baseline = json.load(f)

# Compare
def extract(data):
    pkgs = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                key = (name, tfm, pkg['id'])
                pkgs[key] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    proj, tfm, pkg_id = key
    bv = b.get(key)
    av = a.get(key)
    if bv is None:
        changes.append((proj, tfm, pkg_id, '-', av, 'Added'))
    elif av is None:
        changes.append((proj, tfm, pkg_id, bv, '-', 'Removed'))
    elif bv != av:
        changes.append((proj, tfm, pkg_id, bv, av, 'Aligned to highest'))
    else:
        unchanged.append((proj, tfm, pkg_id, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:<20} {c[1]:<10} {c[2]:<50} {c[3]:<12} -> {c[4]:<12} ({c[5]})')
else:
    print('  None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]:<20} {u[1]:<10} {u[2]:<50} {u[3]}')
"

